    22|export type DeliveryBranchKind = 'remote_db_insert' | 'local_fallback' | 'auth_session_failure' | 'not_observed';
    23|export type RuntimeSourceKind = 'remote_api' | 'local_app_brain' | 'provider_fallback' | string;
