    26|export function resolveSendBranchPure(
    27|  deliveryBranch: DeliveryBranchKind,
    28|  runtimeSource: RuntimeSourceKind,
    29|  httpStatus: string,
    30|): SendBranchProofRow {
    31|  if (deliveryBranch === 'not_observed') {
    32|    return { branch: null, label: 'pending', context: 'no send observed' };
    33|  }
    34|  const statusFragment = httpStatus !== 'pending' && httpStatus !== 'none' ? ` · ${httpStatus}` : '';
    35|  if (deliveryBranch === 'remote_db_insert') {
    36|    if (runtimeSource === 'remote_api' || runtimeSource === 'local_app_brain') {
    37|      return { branch: 'primary_realtime', label: 'primary_realtime', context: `assistant db insert${statusFragment}` };
    38|    }
    39|    if (runtimeSource === 'provider_fallback') {
    40|      return { branch: 'alternate_shared', label: 'alternate_shared', context: `gateway db insert${statusFragment}` };
    41|    }
    42|    return { branch: 'primary_realtime', label: 'primary_realtime', context: `db insert · source ${runtimeSource}${statusFragment}` };
    43|  }
    44|  if (deliveryBranch === 'local_fallback') {
    45|    return { branch: 'snapshot_fallback', label: 'snapshot_fallback', context: `local fallback path${statusFragment}` };
    46|  }
    47|  if (deliveryBranch === 'auth_session_failure') {
    48|    return { branch: 'local_only', label: 'local_only', context: `auth/session unavailable${statusFragment}` };
    49|  }
    50|  return { branch: 'local_only', label: 'local_only', context: `unresolved branch${statusFragment}` };
